def borda(ranked_lists: list[list[str]]) -> list[tuple[str, float]]:
    scores: dict[str, float] = defaultdict(float)
    for ranked in ranked_lists:
        N = len(ranked)
        for rank, doc_id in enumerate(ranked, start=1):
            scores[doc_id] += N - rank      # = N-1 for rank 1, 0 for rank N
    return sorted(scores.items(), key=lambda x: x[1], reverse=True)

import numpy as np

def minmax_normalize(scores: np.ndarray) -> np.ndarray:
    """Per-query min-max normalisation to [0, 1]."""
    mn, mx = scores.min(), scores.max()
    if mx == mn:
        return np.zeros_like(scores)
    return (scores - mn) / (mx - mn)

def z_normalize(scores: np.ndarray) -> np.ndarray:
    """Per-query z-score normalisation (mean 0, std 1)."""
    mu, sigma = scores.mean(), scores.std()
    if sigma == 0:
        return np.zeros_like(scores)
    return (scores - mu) / sigma

def combsum(
    retriever_results: list[tuple[list[str], np.ndarray]],
    normalize_fn=minmax_normalize,
) -> list[tuple[str, float]]:
    """
    retriever_results: list of (doc_ids, raw_scores), one entry per retriever.
    Returns sorted (doc_id, combined_score) pairs.
    """
    combined: dict[str, float] = defaultdict(float)
    for doc_ids, raw_scores in retriever_results:
        norm_scores = normalize_fn(np.asarray(raw_scores, dtype=float))
        for doc_id, score in zip(doc_ids, norm_scores):
            combined[doc_id] += float(score)
    return sorted(combined.items(), key=lambda x: x[1], reverse=True)

def combmnz(
    retriever_results: list[tuple[list[str], np.ndarray]],
    normalize_fn=minmax_normalize,
) -> list[tuple[str, float]]:
    combined: dict[str, float] = defaultdict(float)
    hit_count: dict[str, int] = defaultdict(int)
    for doc_ids, raw_scores in retriever_results:
        norm_scores = normalize_fn(np.asarray(raw_scores, dtype=float))
        for doc_id, score in zip(doc_ids, norm_scores):
            combined[doc_id] += float(score)
            hit_count[doc_id] += 1
    # Multiply by number of retrievers that returned the document
    return sorted(
        [(doc_id, score * hit_count[doc_id]) for doc_id, score in combined.items()],
        key=lambda x: x[1],
        reverse=True,
    )

def weighted_fusion(
    dense_results: tuple[list[str], np.ndarray],
    sparse_results: tuple[list[str], np.ndarray],
    alpha: float = 0.5,
) -> list[tuple[str, float]]:
    """alpha=1.0 → pure dense, alpha=0.0 → pure sparse."""
    combined: dict[str, float] = defaultdict(float)

    d_ids, d_scores = dense_results
    s_ids, s_scores = sparse_results

    d_norm = minmax_normalize(np.asarray(d_scores, dtype=float))
    s_norm = minmax_normalize(np.asarray(s_scores, dtype=float))

    for doc_id, score in zip(d_ids, d_norm):
        combined[doc_id] += alpha * float(score)
    for doc_id, score in zip(s_ids, s_norm):
        combined[doc_id] += (1 - alpha) * float(score)

    return sorted(combined.items(), key=lambda x: x[1], reverse=True)

import numpy as np

def ndcg_at_k(ranked_ids: list[str], relevant_ids: set[str], k: int = 10) -> float:
    """Compute nDCG@k. relevant_ids are binary (in set = relevant)."""
    def dcg(ids):
        return sum(
            (1 if doc_id in relevant_ids else 0) / np.log2(i + 2)
            for i, doc_id in enumerate(ids[:k])
        )
    ideal = sorted([1 if did in relevant_ids else 0 for did in ranked_ids[:k]], reverse=True)
    ideal_dcg = sum(rel / np.log2(i + 2) for i, rel in enumerate(ideal))
    return dcg(ranked_ids) / ideal_dcg if ideal_dcg > 0 else 0.0

